9	    public static function boot(): void
10	    {
11	        self::loadEnv(BASE_PATH . '/.env');
12	        self::configureErrors();
13	        self::startSession();
14	
15	        $config = require BASE_PATH . '/config/config.php';
16	
17	        if (!empty($config['db_host']) && !empty($config['db_name'])) {
18	            Database::connect(
19	                $config['db_host'],
20	                $config['db_port'],
21	                $config['db_name'],
22	                $config['db_user'],
23	                $config['db_pass']
24	            );
25	        }
26	
