31	    private static function loadEnv(string $path): void
32	    {
33	        if (!file_exists($path)) {
34	            return;
35	        }
36	
37	        $lines = file($path, FILE_IGNORE_NEW_LINES | FILE_SKIP_EMPTY_LINES);
38	
39	        foreach ($lines as $line) {
40	            $line = trim($line);
41	
42	            if (str_starts_with($line, '#') || !str_contains($line, '=')) {
43	                continue;
44	            }
45	
46	            [$key, $value] = explode('=', $line, 2);
47	            $key   = trim($key);
48	            $value = trim($value, " \t\n\r\0\x0B\"'");
49	
50	            if (!array_key_exists($key, $_ENV)) {
51	                $_ENV[$key] = $value;
52	                putenv("{$key}={$value}");
53	            }
54	        }
55	    }
56	
57	    private static function configureErrors(): void
58	    {
59	        $env = $_ENV['APP_ENV'] ?? 'production';
60	
61	        error_reporting(E_ALL);
62	
63	        if ($env === 'development') {
64	            ini_set('display_errors', '1');
65	        } else {
66	            ini_set('display_errors', '0');
67	            ini_set('log_errors', '1');
68	        }
69	    }
70	
71	    private static function startSession(): void
72	    {
73	        if (session_status() !== PHP_SESSION_NONE) {
74	            return;
75	        }
76	
77	        session_start([
78	            'cookie_httponly' => true,
79	            'cookie_secure'   => isset($_SERVER['HTTPS']),
80	            'cookie_samesite' => 'Strict',
81	            'use_strict_mode' => true,
82	        ]);
83	
84	        if (empty($_SESSION['csrf_token'])) {
85	            $_SESSION['csrf_token'] = bin2hex(random_bytes(32));
86	        }
87	    }
88	}
